#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long xor = 0;
        for (long long i = L; i <= R; i++) {
            xor ^= i;
        }
        if (xor % 2 == 0) printf("Even\n");
        else printf("Odd\n");
    }
    return 0;
}

