code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long L = sc.nextLong();
            long R = sc.nextLong();
            long xor = 0;
            for (long i = L; i <= R; i++) {
                xor ^= i;
            }
            if (xor % 2 == 0) System.out.println("Even");
            else System.out.println("Odd");
        }
    }
}

