const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [L, R] = readline().split(' ').map(x => parseInt(x));
    let xor = 0;
    for (let j = L; j <= R; j++) {
        xor ^= j;
    }
    if (xor % 2 === 0) console.log('Even');
    else console.log('Odd');
}

